import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Pollutant {
  name: string;
  value: number;
}

interface AirQualityData {
  location: string;
  aqi: {
    value: number;
    category: string;
    pollutants: Pollutant[];
  };
}

export default function Widget() {
  const airQualityData = response.data as AirQualityData;
  const { location, aqi } = airQualityData;
  const { value, category, pollutants } = aqi;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h4" fontWeight={700} color="primary">
              AQI: {value}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Category: {category}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {pollutants.map((pollutant) => (
              <Chip 
                key={pollutant.name}
                label={`${pollutant.name}: ${pollutant.value}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFEB3B' }}
              />
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              height={200}
              series={[
                {
                  data: pollutants.map((pollutant) => ({
                    value: pollutant.value,
                    label: pollutant.name,
                  })),
                  color: ['#FF5722', '#FFC107', '#FF9800', '#FF7043', '#FFCA28'],
                },
              ]}
              sx={{
                '& .MuiPieElement-root': {
                  stroke: '#FFF',
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
